238 |     <script>
239 |         let chatHistory = [];
240 |         const modelName = "gemini-2.5-flash";
241 |         
242 |         let videoConfig = [
243 |             { id: 'A', order: 1, loop: false },
244 |             { id: 'B', order: 2, loop: false },
245 |             { id: 'C', order: 3, loop: true },
246 |             { id: 'D', order: 4, loop: true },
247 |             { id: 'E', order: 5, loop: false },
248 |             { id: 'F', order: 6, loop: false },
249 |             { id: 'G', order: 7, loop: false }
250 |         ];
251 | 
252 |         let currentVidIndex = 0;
253 |         let aiResponseQueue = null;
254 |         let activeTypingId = null;
255 |         let firstMessageTime = 0;
256 |         let isFirstMessage = true;
257 |         let messageSentDuringVid = false;
258 |         let currentLoopCount = 0;
259 |         let messageSentDuringVid = false;
260 |         let currentLoopCount = 0;
261 | 
262 |         const vids = Array.from(document.querySelectorAll('.seq-vid'));
263 | 
264 |         function initVideoManager() {
265 |             const sorted = [...videoConfig].sort((a, b) => a.order - b.order);
266 |             const firstId = sorted.length > 0 ? sorted[0].id : 'A';
267 |             const firstIndex = getVidIndexById(firstId);
268 | 
269 |             vids.forEach((vid, i) => {
270 |                 // Reset all to hidden
271 |                 vid.style.opacity = '0';
272 |                 vid.style.zIndex = '1';
273 |                 
274 |                 vid.addEventListener('ended', () => handleVideoEnded(i));
275 |                 vid.addEventListener('timeupdate', function() {
276 |                     if (this.currentTime > 0.1) {
277 |                         vids.forEach((v, idx) => {
278 |                             if(idx !== currentVidIndex) v.style.opacity = '0';
279 |                         });
280 |                         vids[currentVidIndex].style.opacity = '1';
281 |                     }
282 |                 });
283 |             });
284 | 
285 |             // Set the correctly ordered first video as the visible background (Static until first message)
286 |             if (firstIndex !== -1) {
287 |                 currentVidIndex = firstIndex;
288 |                 vids[firstIndex].style.opacity = '1';
289 |                 vids[firstIndex].style.zIndex = '10';
290 |                 vids[firstIndex].currentTime = 0; 
291 |                 vids[firstIndex].pause(); // Force pause on reload
292 |             }
293 |             renderVideoConfig();
294 |         }
295 | 
296 |         function playVid(index) {
297 |             if (index === -1) return;
298 |             
299 |             const oldIndex = currentVidIndex;
300 |             if (oldIndex !== index) {
301 |                 currentLoopCount = 0;
302 |                 messageSentDuringVid = false;
303 |             } else {
304 |                 currentLoopCount++;
305 |             }
306 | 
307 |             currentVidIndex = index;
308 |             vids[index].style.zIndex = '10';
309 |             vids[index].style.opacity = '1';
310 |             vids[index].currentTime = 0;
311 |             
312 |             const playPromise = vids[index].play();
313 |             if (playPromise !== undefined) {
314 |                 playPromise.then(() => {
315 |                     // Only hide the old video AFTER the new one starts playing to prevent black flicker
316 |                     if (oldIndex !== index) {
317 |                         vids[oldIndex].pause();
318 |                         vids[oldIndex].style.opacity = '0';
319 |                     }
320 |                 }).catch(error => {
321 |                     console.log("Playback blocked, waiting for interaction");
322 |                 });
323 |             }
324 |         }
325 | 
326 |         function getVidIndexById(id) {
327 |             return vids.findIndex(v => {
328 |                 const source = v.querySelector('source');
329 |                 if (!source) return false;
330 |                 const src = source.getAttribute('src');
331 |                 // Match 'A.mp4' regardless of path
332 |                 return src === `${id}.mp4` || src.endsWith(`/${id}.mp4`);
333 |             });
334 |         }
335 | 
336 |         function handleVideoEnded(index) {
337 |             const sorted = [...videoConfig].sort((a, b) => a.order - b.order);
338 |             const currentConf = videoConfig.find(c => getVidIndexById(c.id) === index);
339 |             
340 |             if (aiResponseQueue) {
341 |                 const gIndex = getVidIndexById('G');
342 |                 if (gIndex !== -1 && index !== gIndex) {
343 |                     playVid(gIndex);
344 |                     return;
345 |                 }
346 |             }
347 | 
348 |             if (currentConf && currentConf.loop) {
349 |                 let shouldLoop = false;
350 |                 const cond = currentConf.condition || 'always';
351 |                 const max = parseInt(currentConf.maxLoops) || 0;
352 | 
353 |                 if (cond === 'always') shouldLoop = true;
354 |                 else if (cond === 'onMessage' && messageSentDuringVid) shouldLoop = true;
355 |                 else if (cond === 'onNoMessage' && !messageSentDuringVid) shouldLoop = true;
356 | 
357 |                 // Check loop count limit (0 = infinite)
358 |                 if (shouldLoop && (max === 0 || currentLoopCount < max)) {
359 |                     playVid(index);
360 |                     return;
361 |                 }
362 |             }
363 | 
364 |             const currentPos = sorted.findIndex(c => c.id === (currentConf ? currentConf.id : ''));
365 |             const nextConf = sorted[currentPos + 1] || sorted[0]; 
366 | 
367 |             if (nextConf) {
368 |                 const nextIdx = getVidIndexById(nextConf.id);
369 |                 if (nextIdx !== -1) playVid(nextIdx);
370 |             }
371 |         }
372 | 
373 |         window.onload = () => {
374 |             document.getElementById('api-key').value = localStorage.getItem('aura_api_key') || '';
375 |             document.getElementById('system-prompt').value = localStorage.getItem('aura_system_prompt') || '';
376 |             const savedConfig = localStorage.getItem('aura_video_config');
377 |             if (savedConfig) videoConfig = JSON.parse(savedConfig);
378 |             initVideoManager();
379 |         };
380 | 
381 |         async function sendMessage() {
382 |             const inputElement = document.getElementById('user-input');
383 |             const text = inputElement.value.trim();
384 |             if (!text) return;
385 | 
386 |             messageSentDuringVid = true;
387 | 
388 |             const welcomeMsg = document.getElementById('welcome-msg');
389 |             if (welcomeMsg) welcomeMsg.remove();
390 | 
391 |             appendMessage('user', text);
392 |             inputElement.value = '';
393 |             
394 |             activeTypingId = appendTypingIndicator();
395 |             
396 |             // Start Sequence based on the LOWEST order defined in settings
397 |             if (isFirstMessage) {
398 |                 firstMessageTime = Date.now();
399 |                 const sorted = [...videoConfig].sort((a, b) => a.order - b.order);
400 |                 if (sorted.length > 0) {
401 |                     const firstVidIdx = getVidIndexById(sorted[0].id);
402 |                     if (firstVidIdx !== -1) {
403 |                         setTimeout(() => playVid(firstVidIdx), 2000);
404 |                     }
405 |                 }
406 |             }
407 | 
408 |             const currentVid = vids[currentVidIndex];
409 |             messageSentDuringVid = currentVidIndex;
410 |             isLateSend = (currentVid.duration - currentVid.currentTime) <= 1.0;
411 | 
412 |             // Logic to handle response timing
413 |             const checkAndDisplay = () => {
414 |                 const now = Date.now();
415 |                 const elapsedSinceStart = now - firstMessageTime;
416 |                 
417 |                 if (isFirstMessage) {
418 |                     // First message: Strictly 15 seconds from send
419 |                     if (elapsedSinceStart >= 15000 && aiResponseQueue) {
420 |                         displayAIResponse(aiResponseQueue);
421 |                         aiResponseQueue = null;
422 |                         isFirstMessage = false;
423 |                     } else {
424 |                         setTimeout(checkAndDisplay, 100);
425 |                     }
426 |                 } else {
427 |                     // Subsequent messages: Wait for Video G to reach 3s (finding G dynamically)
428 |                     const gIndex = getVidIndexById('G');
429 |                     if (aiResponseQueue && currentVidIndex === gIndex && vids[gIndex].currentTime >= 3.0) {
430 |                         displayAIResponse(aiResponseQueue);
431 |                         aiResponseQueue = null;
432 |                     } else {
433 |                         setTimeout(checkAndDisplay, 100);
434 |                     }
435 |                 }
436 |             };
437 | 
438 |             // Prepare response immediately
439 |             aiResponseQueue = isFirstMessage ? 
440 |                 "Hello! I'm Aura. I've finished my intro sequence and waited exactly 15 seconds to speak to you." : 
441 |                 "This response was triggered while Video " + (messageSentDuringVid === 3 ? 'D' : 'E') + (isLateSend ? ' was almost over.' : ' was playing.');
442 |             
443 |             checkAndDisplay();
444 |         }
445 | 
446 |         function displayAIResponse(text) {
447 |             if (activeTypingId) {
448 |                 removeTypingIndicator(activeTypingId);
449 |                 activeTypingId = null;
450 |             }
451 |             appendMessage('model', text);
452 |             const container = document.getElementById('chat-container');
453 |             container.scrollTop = container.scrollHeight;
454 |         }
455 | 
456 |         function toggleSidebar() { 
457 |             document.getElementById('sidebar').classList.toggle('closed');
458 |             document.getElementById('sidebar-overlay').classList.toggle('hidden');
459 |         }
460 | 
461 |         function saveSettings() {
462 |             const btn = event.target.closest('button');
463 |             const originalText = btn.innerText;
464 | 
465 |             localStorage.setItem('aura_api_key', document.getElementById('api-key').value);
466 |             localStorage.setItem('aura_system_prompt', document.getElementById('system-prompt').value);
467 |             
468 |             const configRows = document.querySelectorAll('.config-row');
469 |             videoConfig = Array.from(configRows).map(row => ({
470 |                 id: row.dataset.id,
471 |                 order: parseInt(row.querySelector('.order-input').value || 0),
472 |                 loop: row.querySelector('.loop-input').checked,
473 |                 condition: row.querySelector('.cond-input')?.value || 'always',
474 |                 maxLoops: parseInt(row.querySelector('.max-input')?.value || 0)
475 |             }));
476 |             
477 |             localStorage.setItem('aura_video_config', JSON.stringify(videoConfig));
478 |             
479 |             // Visual Feedback
480 |             btn.innerText = "Saved!";
481 |             btn.classList.replace('bg-purple-600', 'bg-green-600');
482 |             
483 |             setTimeout(() => {
484 |                 btn.innerText = originalText;
485 |                 btn.classList.replace('bg-green-600', 'bg-purple-600');
486 |                 toggleSidebar();
487 |                 renderVideoConfig(); // Refresh UI to match sorted state
488 |             }, 800);
489 |         }
490 | 
491 |         function renderVideoConfig() {
492 |             const list = document.getElementById('video-config-list');
493 |             if (!list) return;
494 |             list.innerHTML = '';
495 |             const sorted = [...videoConfig].sort((a,b) => a.order - b.order);
496 |             sorted.forEach(conf => {
497 |                 const div = document.createElement('div');
498 |                 div.className = 'config-row flex flex-col gap-2 bg-white/5 p-3 rounded-lg border border-white/10';
499 |                 div.dataset.id = conf.id;
500 |                 div.innerHTML = `
501 |                     <div class="flex items-center gap-2">
502 |                         <span class="text-white font-bold w-6">${conf.id}</span>
503 |                         <input type="number" class="order-input w-10 bg-black/20 border border-white/20 rounded px-1 text-xs text-white" value="${conf.order}">
504 |                         <label class="flex items-center gap-1 text-[10px] text-white/60">
505 |                             <input type="checkbox" class="loop-input" ${conf.loop ? 'checked' : ''} onchange="renderVideoConfig()"> Loop
506 |                         </label>
507 |                         <button onclick="removeVideoConfig('${conf.id}')" class="ml-auto text-red-400 text-xs p-1"><i class="fa-solid fa-trash"></i></button>
508 |                     </div>
509 |                     ${conf.loop ? `
510 |                     <div class="grid grid-cols-2 gap-2 mt-1 border-t border-white/5 pt-2">
511 |                         <div class="flex flex-col gap-1">
512 |                             <label class="text-[9px] text-white/40 uppercase">Condition</label>
513 |                             <select class="cond-input bg-black/40 text-white text-[10px] rounded border border-white/10 p-1">
514 |                                 <option value="always" ${conf.condition === 'always' ? 'selected' : ''}>Always</option>
515 |                                 <option value="onMessage" ${conf.condition === 'onMessage' ? 'selected' : ''}>On Message</option>
516 |                                 <option value="onNoMessage" ${conf.condition === 'onNoMessage' ? 'selected' : ''}>On No Message</option>
517 |                             </select>
518 |                         </div>
519 |                         <div class="flex flex-col gap-1">
520 |                             <label class="text-[9px] text-white/40 uppercase">Max Loops</label>
521 |                             <input type="number" class="max-input bg-black/40 text-white text-[10px] rounded border border-white/10 p-1" 
522 |                                 value="${conf.maxLoops || 0}" placeholder="0 = infinite">
523 |                         </div>
524 |                     </div>
525 |                     ` : ''}
526 |                 `;
527 |                 list.appendChild(div);
528 |             });
529 |         }
