536 |         function addVideoConfig() {
537 |             const name = prompt("Enter Video Name (e.g. H):");
538 |             if (!name) return;
539 |             const nextOrder = videoConfig.length > 0 ? Math.max(...videoConfig.map(c => c.order)) + 1 : 1;
540 |             videoConfig.push({ id: name.toUpperCase(), order: nextOrder, loop: false });
541 |             renderVideoConfig();
542 |         }
