544 |         function appendMessage(role, text) {
545 |             const container = document.getElementById('chat-container');
546 |             const div = document.createElement('div');
547 |             div.className = `p-4 max-w-[85%] ${role === 'user' ? 'message-user' : 'message-ai'}`;
548 |             div.innerText = text;
549 |             container.appendChild(div);
550 |             container.scrollTop = container.scrollHeight;
551 |         }
